import (
	"context"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/rs/zerolog"
	"github.com/rs/zerolog/log"

	"fitcommerce/backend/internal/config"
	"fitcommerce/backend/internal/database"
)

func main() {
	log.Logger = zerolog.New(os.Stdout).With().Timestamp().Str("service", "worker").Logger()

	cfg, err := config.Load()
	if err != nil {
		log.Fatal().Err(err).Msg("failed to load config")
	}
	log.Info().Str("env", cfg.Env).Msg("starting fitcommerce worker")

	pool, err := database.Connect(cfg.DB.URL)
	if err != nil {
		log.Fatal().Err(err).Msg("database connection failed")
	}
	defer pool.Close()

	redisOpts, err := redis.ParseURL(cfg.Redis.URL)
	if err != nil {
		log.Fatal().Err(err).Msg("invalid redis url")
	}
	rdb := redis.NewClient(redisOpts)
	defer rdb.Close()

	ctx, cancel := context.WithCancel(context.Background())

	// ── Job loops ─────────────────────────────────────────────────
	go runGroupBuyCutoffLoop(ctx, pool, rdb)
	go runExportJobLoop(ctx, pool, rdb, cfg.ExportDir)

	// ── Graceful shutdown ─────────────────────────────────────────
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	log.Info().Msg("shutting down worker")
	cancel()
	time.Sleep(2 * time.Second) // allow in-flight jobs to finish
	log.Info().Msg("worker stopped")
}

// runGroupBuyCutoffLoop polls for active group-buys past their cutoff and evaluates them.
func runGroupBuyCutoffLoop(ctx context.Context, pool interface{ Close() }, rdb *redis.Client) {
	ticker := time.NewTicker(30 * time.Second)
	defer ticker.Stop()
	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			log.Debug().Msg("group-buy cutoff evaluation tick")
			// TODO: implemented in group-buys prompt
		}
	}
}

// runExportJobLoop drains the export job queue.
func runExportJobLoop(ctx context.Context, pool interface{ Close() }, rdb *redis.Client, exportDir string) {
	ticker := time.NewTicker(5 * time.Second)
	defer ticker.Stop()
	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			log.Debug().Msg("export job queue drain tick")
			// TODO: implemented in exports prompt
		}
	}
}
"}

