12	type Claims struct {
13		UserID string `json:"user_id"`
14		Email  string `json:"email"`
15		Role   string `json:"role"`
16		jwt.RegisteredClaims
17	}
18	
19	type TokenPair struct {
20		AccessToken  string `json:"access_token"`
21		RefreshToken string `json:"refresh_token"`
22		ExpiresIn    int64  `json:"expires_in"`
23	}
24	
25	type Manager struct {
26		cfg *config.JWTConfig
27	}
28	
29	func NewManager(cfg *config.JWTConfig) *Manager {
30		return &Manager{cfg: cfg}
31	}
32	
33	func (m *Manager) Issue(userID, email, role string) (*TokenPair, error) {
34		now := time.Now()
35	
36		accessClaims := &Claims{
37			UserID: userID,
38			Email:  email,
39			Role:   role,
40			RegisteredClaims: jwt.RegisteredClaims{
41				ExpiresAt: jwt.NewNumericDate(now.Add(m.cfg.AccessTTL)),
42				IssuedAt:  jwt.NewNumericDate(now),
43				ID:        uuid.New().String(),
44			},
45		}
46		accessToken, err := jwt.NewWithClaims(jwt.SigningMethodHS256, accessClaims).
47			SignedString([]byte(m.cfg.Secret))
48		if err != nil {
49			return nil, err
50		}
51	
52		refreshClaims := &Claims{
53			UserID: userID,
54			RegisteredClaims: jwt.RegisteredClaims{
55				ExpiresAt: jwt.NewNumericDate(now.Add(m.cfg.RefreshTTL)),
56				IssuedAt:  jwt.NewNumericDate(now),
57				ID:        uuid.New().String(),
58			},
59		}
60		refreshToken, err := jwt.NewWithClaims(jwt.SigningMethodHS256, refreshClaims).
61			SignedString([]byte(m.cfg.RefreshSecret))
62		if err != nil {
63			return nil, err
64		}
65	
66		return &TokenPair{
67			AccessToken:  accessToken,
68			RefreshToken: refreshToken,
69			ExpiresIn:    int64(m.cfg.AccessTTL.Seconds()),
70		}, nil
71	}
72	
73	func (m *Manager) Validate(tokenStr string) (*Claims, error) {
74		return m.parse(tokenStr, m.cfg.Secret)
75	}
76	
77	func (m *Manager) ValidateRefresh(tokenStr string) (*Claims, error) {
78		return m.parse(tokenStr, m.cfg.RefreshSecret)
79	}
80	
81	func (m *Manager) parse(tokenStr, secret string) (*Claims, error) {
82		token, err := jwt.ParseWithClaims(tokenStr, &Claims{}, func(t *jwt.Token) (interface{}, error) {
83			if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
84				return nil, errors.New("unexpected signing method")
85			}
86			return []byte(secret), nil
87		})
88		if err != nil {
89			return nil, err
90		}
91		claims, ok := token.Claims.(*Claims)
92		if !ok || !token.Valid {
93			return nil, errors.New("invalid token")
94		}
95		return claims, nil
96	}
