1	package auth
2	
3	import (
4		"errors"
5		"time"
6	
7		"github.com/golang-jwt/jwt/v5"
8		"github.com/google/uuid"
9		"fitcommerce/backend/internal/config"
10	)
11	
12	type Claims struct {
13		UserID string `json:"user_id"`
14		Email  string `json:"email"`
15		Role   string `json:"role"`
16		jwt.RegisteredClaims
17	}
18	
19	type TokenPair struct {
20		AccessToken  string `json:"access_token"`
21		RefreshToken string `json:"refresh_token"`
22		ExpiresIn    int64  `json:"expires_in"`
23	}
24	
25	type Manager struct {
26		cfg *config.JWTConfig
27	}
28	
29	func NewManager(cfg *config.JWTConfig) *Manager {
30		return &Manager{cfg: cfg}
31	}
32	
33	func (m *Manager) Issue(userID, email, role string) (*TokenPair, error) {
34		now := time.Now()
35	
36		accessClaims := &Claims{
37			UserID: userID,
38			Email:  email,
39			Role:   role,
40			RegisteredClaims: jwt.RegisteredClaims{
41				ExpiresAt: jwt.NewNumericDate(now.Add(m.cfg.AccessTTL)),
42				IssuedAt:  jwt.NewNumericDate(now),
43				ID:        uuid.New().String(),
44			},
45		}
46		accessToken, err := jwt.NewWithClaims(jwt.SigningMethodHS256, accessClaims).
47			SignedString([]byte(m.cfg.Secret))
48		if err != nil {
49			return nil, err
50		}
51	
52		refreshClaims := &Claims{
53			UserID: userID,
54			RegisteredClaims: jwt.RegisteredClaims{
55				ExpiresAt: jwt.NewNumericDate(now.Add(m.cfg.RefreshTTL)),
56				IssuedAt:  jwt.NewNumericDate(now),
57				ID:        uuid.New().String(),
58			},
59		}
60		refreshToken, err := jwt.NewWithClaims(jwt.SigningMethodHS256, refreshClaims).
61			SignedString([]byte(m.cfg.RefreshSecret))
62		if err != nil {
63			return nil, err
64		}
65	
66		return &TokenPair{
67			AccessToken:  accessToken,
68			RefreshToken: refreshToken,
69			ExpiresIn:    int64(m.cfg.AccessTTL.Seconds()),
70		}, nil
71	}
72	
73	func (m *Manager) Validate(tokenStr string) (*Claims, error) {
74		return m.parse(tokenStr, m.cfg.Secret)
75	}
76	
77	func (m *Manager) ValidateRefresh(tokenStr string) (*Claims, error) {
78		return m.parse(tokenStr, m.cfg.RefreshSecret)
79	}
80	
81	// GetRefreshTTL exposes the configured refresh token TTL for callers that
82	// need to compute an expiry timestamp when storing tokens.
83	func (m *Manager) GetRefreshTTL() time.Duration {
84		return m.cfg.RefreshTTL
85	}
86	
87	func (m *Manager) parse(tokenStr, secret string) (*Claims, error) {
88		token, err := jwt.ParseWithClaims(tokenStr, &Claims{}, func(t *jwt.Token) (interface{}, error) {
89			if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
90				return nil, errors.New("unexpected signing method")
91			}
92			return []byte(secret), nil
93		})
94		if err != nil {
95			return nil, err
96		}
97		claims, ok := token.Claims.(*Claims)
98		if !ok || !token.Valid {
99			return nil, errors.New("invalid token")
100		}
101		return claims, nil
102	}
103

1	package middleware
2	
3	import (
4		"net/http"
5		"strings"
6		"time"
7	
8		"github.com/gin-gonic/gin"
9		"github.com/google/uuid"
10		"github.com/rs/zerolog"
11	
12		"fitcommerce/backend/internal/auth"
13	)
14	
15	const (
16		KeyUserID    = "user_id"
17		KeyEmail     = "email"
18		KeyRole      = "role"
19		KeyRequestID = "request_id"
20	)
21	
22	// RequestID injects a unique request ID into every request.
23	func RequestID() gin.HandlerFunc {
24		return func(c *gin.Context) {
25			id := c.GetHeader("X-Request-ID")
26			if id == "" {
27				id = uuid.New().String()
28			}
29			c.Set(KeyRequestID, id)
30			c.Header("X-Request-ID", id)
31			c.Next()
32		}
33	}
34	
35	// Logger logs structured request info via zerolog.
36	func Logger(log *zerolog.Logger) gin.HandlerFunc {
37		return func(c *gin.Context) {
38			start := time.Now()
39			path := c.Request.URL.Path
40			c.Next()
41			log.Info().
42				Str("method", c.Request.Method).
43				Str("path", path).
44				Int("status", c.Writer.Status()).
45				Dur("latency", time.Since(start)).
46				Str("request_id", c.GetString(KeyRequestID)).
47				Str("ip", c.ClientIP()).
48				Msg("request")
49		}
50	}
51	
52	// Auth validates the Bearer JWT and sets user context keys.
53	func Auth(jwtManager *auth.Manager) gin.HandlerFunc {
54		return func(c *gin.Context) {
55			header := c.GetHeader("Authorization")
56			if !strings.HasPrefix(header, "Bearer ") {
57				c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
58					"error": gin.H{"code": "UNAUTHORIZED", "message": "missing bearer token"},
59				})
60				return
61			}
62			token := strings.TrimPrefix(header, "Bearer ")
63			claims, err := jwtManager.Validate(token)
64			if err != nil {
65				c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
66					"error": gin.H{"code": "INVALID_TOKEN", "message": "invalid or expired token"},
67				})
68				return
69			}
70			c.Set(KeyUserID, claims.UserID)
71			c.Set(KeyEmail, claims.Email)
72			c.Set(KeyRole, claims.Role)
73			c.Next()
74		}
75	}
76	
77	// RequireRoles enforces RBAC — only listed roles may proceed.
78	func RequireRoles(roles ...string) gin.HandlerFunc {
79		allowed := make(map[string]bool, len(roles))
80		for _, r := range roles {
81			allowed[r] = true
82		}
83		return func(c *gin.Context) {
84			role := c.GetString(KeyRole)
85			if !allowed[role] {
86				c.AbortWithStatusJSON(http.StatusForbidden, gin.H{
87					"error": gin.H{"code": "FORBIDDEN", "message": "insufficient permissions"},
88				})
89				return
90			}
91			c.Next()
92		}
93	}
94	
95	// CORS sets cross-origin headers for listed origins.
96	func CORS(allowedOrigins []string) gin.HandlerFunc {
97		origins := make(map[string]bool, len(allowedOrigins))
98		for _, o := range allowedOrigins {
99			origins[o] = true
100		}
101		return func(c *gin.Context) {
102			origin := c.GetHeader("Origin")
103			if origins[origin] || origins["*"] {
104				c.Header("Access-Control-Allow-Origin", origin)
105				c.Header("Access-Control-Allow-Methods", "GET,POST,PUT,PATCH,DELETE,OPTIONS")
106				c.Header("Access-Control-Allow-Headers", "Content-Type,Authorization,X-Request-ID")
107				c.Header("Access-Control-Expose-Headers", "X-Request-ID")
108				c.Header("Access-Control-Allow-Credentials", "true")
109			}
110			if c.Request.Method == http.MethodOptions {
111				c.AbortWithStatus(http.StatusNoContent)
112				return
113			}
114			c.Next()
115		}
116	}
