1	import { create } from 'zustand';
2	import { getAccessToken, getRefreshToken, setTokens, clearTokens } from '../api/client';
3	import { login as apiLogin, logout as apiLogout, getMe } from '../api/auth';
4	import type { User } from '../types/auth';
5	
6	interface AuthState {
7	  user: User | null;
8	  isAuthenticated: boolean;
9	  isLoading: boolean;
10	  error: string | null;
11	
12	  login: (email: string, password: string) => Promise<void>;
13	  logout: () => Promise<void>;
14	  restoreSession: () => Promise<void>;
15	  clearError: () => void;
16	  // Called by the API client on auth:logout event
17	  forceLogout: () => void;
18	}
19	
20	export const useAuthStore = create<AuthState>((set, get) => ({
21	  user: null,
22	  isAuthenticated: false,
23	  isLoading: true,
24	  error: null,
25	
26	  login: async (email, password) => {
27	    set({ isLoading: true, error: null });
28	    try {
29	      const data = await apiLogin(email, password);
30	      setTokens(data.access_token, data.refresh_token);
31	      set({ user: data.user, isAuthenticated: true, isLoading: false, error: null });
32	    } catch (err) {
33	      const message =
34	        err instanceof Error ? err.message : 'Login failed. Check your credentials.';
35	      set({ isLoading: false, error: message, isAuthenticated: false, user: null });
36	      throw err;
37	    }
38	  },
39	
40	  logout: async () => {
41	    const refreshToken = getRefreshToken();
42	    try {
43	      if (refreshToken) await apiLogout(refreshToken);
44	    } catch {
45	      // Ignore logout API errors
46	    } finally {
47	      clearTokens();
48	      set({ user: null, isAuthenticated: false, isLoading: false, error: null });
49	    }
50	  },
51	
52	  restoreSession: async () => {
53	    set({ isLoading: true });
54	    const accessToken = getAccessToken();
55	    if (!accessToken) {
56	      set({ isLoading: false, isAuthenticated: false });
57	      return;
58	    }
59	    try {
60	      const user = await getMe();
61	      set({ user, isAuthenticated: true, isLoading: false });
62	    } catch {
63	      // Token expired or invalid — clearTokens is handled by the API client's
64	      // refresh flow; if refresh also failed, the auth:logout event fires.
65	      clearTokens();
66	      set({ user: null, isAuthenticated: false, isLoading: false });
67	    }
68	  },
69	
70	  clearError: () => set({ error: null }),
71	
72	  forceLogout: () => {
73	    clearTokens();
74	    set({ user: null, isAuthenticated: false, isLoading: false });
75	  },
76	}));
77	
78	// Listen for the global logout event emitted by the API client when refresh fails
79	if (typeof window !== 'undefined') {
80	  window.addEventListener('auth:logout', () => {
81	    useAuthStore.getState().forceLogout();
82	  });
83	}
