12	export function ProtectedRoute({ children, roles }: Props) {
13	  const { isAuthenticated, isLoading, user } = useAuthStore();
14	  const location = useLocation();
15	
16	  if (isLoading) {
17	    return (
18	      <Box display="flex" alignItems="center" justifyContent="center" minHeight="100vh">
19	        <CircularProgress />
20	      </Box>
21	    );
22	  }
23	
24	  if (!isAuthenticated) {
25	    return <Navigate to="/login" state={{ from: location.pathname }} replace />;
26	  }
27	
28	  if (roles && user && !roles.includes(user.role)) {
29	    return <Navigate to="/forbidden" replace />;
30	  }
31	
32	  return <>{children}</>;
33	}
34	
35	/** Inline guard that hides UI sections without a full redirect */
36	export function RoleGuard({ children, roles }: Props) {
37	  const { user } = useAuthStore();
38	  if (!user || (roles && !roles.includes(user.role))) return null;
39	  return <>{children}</>;
40	}
