import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/redis/go-redis/v9"
	"github.com/rs/zerolog"

	"fitcommerce/backend/internal/auth"
	"fitcommerce/backend/internal/config"
	appRouter "fitcommerce/backend/internal/http/router"
)

// testEnv bundles the dependencies a test needs to drive the API.
type testEnv struct {
	Router *gin.Engine
	DB     *pgxpool.Pool
	JWT    *auth.Manager
}

// setupRouter builds a real Gin engine backed by the test database.
// The caller is expected to have a running Postgres instance seeded by Docker.
// If the pool cannot connect, the test is skipped.
func setupRouter(t *testing.T) *testEnv {
	t.Helper()
	gin.SetMode(gin.TestMode)

	// Use real test database if available; otherwise skip.
	cfg := testConfig()

	pool, err := connectTestDB(cfg.DB.URL)
	if err != nil {
		t.Skipf("cannot connect to test DB (skipping integration test): %v", err)
	}
	t.Cleanup(func() { pool.Close() })

	rdb := redis.NewClient(&redis.Options{Addr: "localhost:6379"})

	jwtMgr := auth.NewManager(&cfg.JWT)
	log := zerolog.Nop()

	r := appRouter.New(cfg, pool, rdb, jwtMgr, &log)

	return &testEnv{Router: r, DB: pool, JWT: jwtMgr}
}

func testConfig() *config.Config {
	jwtCfg := auth.TestJWTConfig()
	return &config.Config{
		Env:       "test",
		Port:      "0",
		ExportDir: "/tmp/exports",
		DB:        config.DBConfig{URL: "postgres://fitcommerce:fitcommerce@localhost:5432/fitcommerce_test?sslmode=disable"},
		Redis:     config.RedisConfig{URL: "redis://localhost:6379"},
		JWT:       jwtCfg,
		CORS:      config.CORSConfig{AllowedOrigins: []string{"*"}},
	}
}

func connectTestDB(dsn string) (*pgxpool.Pool, error) {
	ctx := contextBG()
	poolCfg, err := pgxpool.ParseConfig(dsn)
	if err != nil {
		return nil, err
	}
	poolCfg.MaxConns = 5
	pool, err := pgxpool.NewWithConfig(ctx, poolCfg)
	if err != nil {
		return nil, err
	}
	if err := pool.Ping(ctx); err != nil {
		pool.Close()
		return nil, err
	}
	return pool, nil
}

// ── HTTP helpers ──────────────────────────────────────────────────────────────

func doPost(router *gin.Engine, path string, body interface{}, token ...string) *httptest.ResponseRecorder {
	b, _ := json.Marshal(body)
	req := httptest.NewRequest(http.MethodPost, path, bytes.NewReader(b))
	req.Header.Set("Content-Type", "application/json")
	if len(token) > 0 && token[0] != "" {
		req.Header.Set("Authorization", "Bearer "+token[0])
	}
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)
	return w
}

func doGet(router *gin.Engine, path string, token string) *httptest.ResponseRecorder {
	req := httptest.NewRequest(http.MethodGet, path, nil)
	req.Header.Set("Content-Type", "application/json")
	if token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)
	return w
}

func parseBody(w *httptest.ResponseRecorder) map[string]interface{} {
	var result map[string]interface{}
	_ = json.Unmarshal(w.Body.Bytes(), &result)
	return result
}

func contextBG() interface{ Deadline() (interface{}, bool) } {
	// just return a stdlib background context
	return nil
}
"}

