  id: '1',
  email: 'admin@test.com',
  first_name: 'Admin',
  last_name: 'User',
  role: 'administrator',
};

const mockTokenPair: TokenPair = {
  access_token: 'at',
  refresh_token: 'rt',
  expires_in: 900,
  user: mockUser,
};

function resetStore() {
  useAuthStore.setState({
    user: null,
    isAuthenticated: false,
    isLoading: false,
    error: null,
  });
