  first_name: 'Member',
  last_name: 'User',
  role: 'member',
};

function resetStore(overrides: Partial<ReturnType<typeof useAuthStore.getState>> = {}) {
  useAuthStore.setState({
    user: null,
    isAuthenticated: false,
    isLoading: false,
    error: null,
    ...overrides,
  });
}

