		sets = append(sets, fmt.Sprintf("billing_model = $%d", argIdx))
		args = append(args, *req.BillingModel)
		argIdx++
	}
	if req.Price != nil {
		sets = append(sets, fmt.Sprintf("price = $%d", argIdx))
		args = append(args, *req.Price)
