			&a.AdjustedBy, &createdAt); err != nil {
			response.InternalError(c)
			return
		}
		a.CreatedAt = createdAt.UTC().Format(time.RFC3339)
		adjs = append(adjs, a)
	}

	response.OK(c, adjs)
}
"}

