	if page < 1 {
		page = 1
	}
	if perPage < 1 || perPage > 100 {
		perPage = 25
	}

	var total int
	_ = h.db.QueryRow(c.Request.Context(), `SELECT COUNT(*) FROM inventory_stock`).Scan(&total)

	rows, err := h.db.Query(c.Request.Context(), `
