      {
        path: 'suppliers',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <PlaceholderPage title="Suppliers" />
          </ProtectedRoute>
        ),
      },

      // ── Purchase Orders ──────────────────────────────────────────────────
      {
        path: 'purchase-orders',
        element: (
          <ProtectedRoute roles={['administrator', 'procurement_specialist']}>
            <PlaceholderPage title="Purchase Orders" />
          </ProtectedRoute>
        ),
      },

      // ── Other modules ────────────────────────────────────────────────────
      {
        path: 'group-buys',
        element: <PlaceholderPage title="Group Buys" />,
      },
      {
        path: 'orders',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'member']}>
            <PlaceholderPage title="Orders" />
          </ProtectedRoute>
        ),
      },
      {
        path: 'reports',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'coach']}>
            <PlaceholderPage title="Reports" />
          </ProtectedRoute>
        ),
      },
      {
        path: 'classes',
        element: (
          <ProtectedRoute roles={['administrator', 'operations_manager', 'coach']}>
            <PlaceholderPage title="Classes" />
          </ProtectedRoute>
        ),
      },
      {
        path: 'admin',
        element: (
          <ProtectedRoute roles={['administrator']}>
            <PlaceholderPage title="Administration" />
          </ProtectedRoute>
        ),
      },
    ],
  },

  // Catch-all
  { path: '*', element: <Navigate to="/dashboard" replace /> },
]);
"}

