export interface GroupBuy {
  id: string;
  item_id: string;
  location_id: string;
  created_by: string | null;
  title: string;
  description: string | null;
  min_quantity: number;
  current_quantity: number;
  status: string;
  cutoff_at: string;
  price_per_unit: number;
  notes: string | null;
  created_at: string;
  updated_at: string;
  version: number;
  progress: number;
}

export interface GroupBuyListResponse {
  data: GroupBuy[];
  meta: { page: number; per_page: number; total: number };
}

export interface Participant {
  id: string;
  group_buy_id: string;
  member_id: string;
  quantity: number;
  joined_at: string;
  status: string;
}

export interface CreateGroupBuyPayload {
  item_id: string;
  location_id: string;
  title: string;
  description?: string;
  min_quantity: number;
  cutoff_at: string;
  price_per_unit: number;
  notes?: string;
}

export async function listGroupBuys(params?: Record<string, string>): Promise<GroupBuyListResponse> {
  const qs = params ? '?' + new URLSearchParams(params).toString() : '';
  const res = await fetch(
    `${import.meta.env.VITE_API_URL ?? 'http://localhost:8080'}/api/v1/group-buys${qs}`,
    {
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${localStorage.getItem('fc_access_token')}`,
      },
    },
  );
  return res.json();
}

export function getGroupBuy(id: string): Promise<GroupBuy> {
  return apiRequest<GroupBuy>(`/api/v1/group-buys/${id}`);
}

export function createGroupBuy(payload: CreateGroupBuyPayload): Promise<GroupBuy> {
  return apiRequest<GroupBuy>('/api/v1/group-buys', {
    method: 'POST',
    body: JSON.stringify(payload),
  });
}

export function publishGroupBuy(id: string): Promise<GroupBuy> {
  return apiRequest<GroupBuy>(`/api/v1/group-buys/${id}/publish`, { method: 'POST' });
}

export function cancelGroupBuy(id: string): Promise<void> {
  return apiRequest(`/api/v1/group-buys/${id}/cancel`, { method: 'POST' });
}

export function joinGroupBuy(id: string, quantity?: number): Promise<Participant> {
  return apiRequest<Participant>(`/api/v1/group-buys/${id}/join`, {
    method: 'POST',
    body: JSON.stringify({ quantity: quantity ?? 1 }),
  });
}

export function leaveGroupBuy(id: string): Promise<void> {
  return apiRequest(`/api/v1/group-buys/${id}/leave`, { method: 'DELETE' });
}

export function getParticipants(id: string): Promise<Participant[]> {
  return apiRequest<Participant[]>(`/api/v1/group-buys/${id}/participants`);
}
"}

