func (h *Handler) listNotes(c *gin.Context) {
	orderID := c.Param("id")
	role := c.GetString(middleware.KeyRole)

	// Members only see notes on their own orders
	if role == auth.RoleMember {
		userID := c.GetString(middleware.KeyUserID)
