	_ = h.db.QueryRow(ctx, `SELECT COUNT(*) FROM inventory_stock WHERE on_hand < 5`).Scan(&s.LowStock)

	response.OK(c, s)
}

// ── KPI: Group Buys Report ────────────────────────────────────────────────────

func (h *Handler) groupBuysReport(c *gin.Context) {
	ctx := c.Request.Context()
