	response.OK(c, gin.H{
		"coach_id":          coachID,
		"total_classes":     totalClasses,
		"completed_classes": completedClasses,
		"total_attendees":   totalAttendees,
		"avg_fill_rate":     avgFillRate,
		"start_date":        start.Format("2006-01-02"),
		"end_date":          end.Format("2006-01-02"),
	})
}
"}

