// ── Types ─────────────────────────────────────────────────────────────────────

type createExportRequest struct {
	ReportType string            `json:"report_type" binding:"required"`
	Format     string            `json:"format" binding:"required"`
	Filters    map[string]string `json:"filters"`
}

type exportResponse struct {
