2	import { getPendingMutations, markApplied, markRejected, scheduleRetry } from './offlineQueue';
3	import type { EntityType, SyncStatus } from './types';
4	
5	const API_BASE = import.meta.env.VITE_API_URL ?? 'http://localhost:8080';
6	const SYNC_ENTITIES: EntityType[] = ['items', 'group_buys', 'orders', 'members'];
7	const MAX_RETRIES = 5;
8	
9	type StatusListener = (status: SyncStatus) => void;
10	
11	class SyncManager {
12	  private status: SyncStatus = 'offline';
13	  private listeners = new Set<StatusListener>();
14	  private draining = false;
15	  private onlineHandler: () => void;
16	  private offlineHandler: () => void;
17	
18	  constructor() {
19	    this.onlineHandler = () => this.handleOnline();
20	    this.offlineHandler = () => this.handleOffline();
21	  }
22	
23	  start(): void {
24	    window.addEventListener('online', this.onlineHandler);
25	    window.addEventListener('offline', this.offlineHandler);
26	
27	    // Bootstrap — check current connectivity
28	    if (navigator.onLine) {
29	      this.setStatus('online');
30	      void this.drainQueue();
31	      void this.pullChanges();
32	    } else {
33	      this.setStatus('offline');
34	    }
35	  }
36	
37	  stop(): void {
38	    window.removeEventListener('online', this.onlineHandler);
39	    window.removeEventListener('offline', this.offlineHandler);
40	  }
41	
42	  subscribe(fn: StatusListener): () => void {
43	    this.listeners.add(fn);
44	    fn(this.status); // emit current status immediately
45	    return () => this.listeners.delete(fn);
46	  }
47	
48	  getStatus(): SyncStatus {
49	    return this.status;
50	  }
51	
52	  // ── Internal ───────────────────────────────────────────────────────────────
53	
54	  private setStatus(s: SyncStatus): void {
55	    if (this.status === s) return;
56	    this.status = s;
57	    this.listeners.forEach(fn => fn(s));
58	  }
59	
60	  private handleOnline(): void {
61	    this.setStatus('online');
62	    void this.drainQueue();
63	    void this.pullChanges();
64	  }
65	
66	  private handleOffline(): void {
67	    this.setStatus('offline');
68	  }
69	
70	  /**
71	   * Drain the local mutation queue by pushing pending mutations to the server.
72	   * Runs serially to maintain causality.
73	   */
74	  async drainQueue(): Promise<void> {
75	    if (this.draining || !navigator.onLine) return;
76	    this.draining = true;
77	    this.setStatus('syncing');
78	
79	    try {
80	      const pending = await getPendingMutations();
81	      for (const mutation of pending) {
82	        if (!navigator.onLine) break;
83	        if (mutation.retry_count >= MAX_RETRIES) {
84	          await markRejected(mutation.seq!, 'max retries exceeded');
85	          continue;
86	        }
87	
88	        try {
89	          const res = await fetch(`${API_BASE}/api/v1/sync/push`, {
90	            method: 'POST',
91	            headers: {
92	              'Content-Type': 'application/json',
93	              Authorization: `Bearer ${getAccessToken()}`,
94	            },
95	            body: JSON.stringify({
96	              mutations: [
97	                {
98	                  idempotency_key: mutation.idempotency_key,
99	                  client_id: mutation.client_id,
100	                  entity_type: mutation.entity_type,
101	                  entity_id: mutation.entity_id,
102	                  operation: mutation.operation,
103	                  payload: mutation.payload,
104	                },
105	              ],
106	            }),
107	          });
108	
109	          if (res.ok) {
110	            await markApplied(mutation.seq!);
111	          } else if (res.status === 409) {
112	            // Conflict — server has a newer version
113	            const body = await res.json();
114	            await db.conflicts.add({
115	              mutation_seq: mutation.seq!,
116	              entity_type: mutation.entity_type,
117	              entity_id: mutation.entity_id ?? '',
118	              client_payload: mutation.payload,
119	              server_payload: body?.data ?? {},
120	              detected_at: Date.now(),
121	            });
122	            await markRejected(mutation.seq!, 'conflict');
123	          } else if (res.status >= 400 && res.status < 500) {
124	            await markRejected(mutation.seq!, `server rejected: ${res.status}`);
125	          } else {
126	            await scheduleRetry(mutation.seq!);
127	          }
128	        } catch {
129	          await scheduleRetry(mutation.seq!);
130	        }
131	      }
132	    } finally {
133	      this.draining = false;
134	      this.setStatus(navigator.onLine ? 'online' : 'offline');
135	    }
136	  }
137	
138	  /**
139	   * Pull server-side changes since the last known timestamp for each entity.
140	   */
141	  async pullChanges(): Promise<void> {
142	    if (!navigator.onLine) return;
143	
144	    for (const entityType of SYNC_ENTITIES) {
145	      try {
146	        const meta = await db.syncMeta.get(entityType);
147	        const since = meta?.last_synced_at ?? 0;
148	
149	        const res = await fetch(
150	          `${API_BASE}/api/v1/sync/changes?since=${Math.floor(since / 1000)}&entities=${entityType}`,
151	          {
152	            headers: { Authorization: `Bearer ${getAccessToken()}` },
153	          },
154	        );
155	
156	        if (!res.ok) continue;
157	
158	        const { data, synced_at } = await res.json();
159	
160	        // Hydrate local cache tables
161	        if (Array.isArray(data)) {
162	          await hydrate(entityType, data);
163	        }
164	
165	        // Update sync cursor
166	        await db.syncMeta.put({ entity_type: entityType, last_synced_at: synced_at * 1000 });
167	      } catch {
168	        // Network failure during pull — silently continue; we'll retry on next reconnect
169	      }
170	    }
171	  }
172	}
