174	// ── Helpers ───────────────────────────────────────────────────────────────────
175	
176	function getAccessToken(): string {
177	  return localStorage.getItem('access_token') ?? '';
178	}
179	
180	async function hydrate(entityType: EntityType, records: Record<string, unknown>[]): Promise<void> {
181	  const now = Date.now();
182	  const withTimestamp = records.map(r => ({ ...r, cached_at: now }));
183	
184	  switch (entityType) {
185	    case 'items':
186	      await db.items.bulkPut(withTimestamp as never);
187	      break;
188	    case 'group_buys':
189	      await db.groupBuys.bulkPut(withTimestamp as never);
190	      break;
191	    case 'orders':
192	      await db.orders.bulkPut(withTimestamp as never);
193	      break;
194	    case 'members':
195	      await db.members.bulkPut(withTimestamp as never);
196	      break;
197	  }
198	}
