3	import type { EntityType, MutationOperation, QueuedMutation } from './types';
4	
5	const CLIENT_ID_KEY = 'fitcommerce_client_id';
6	
7	function getClientId(): string {
8	  let id = localStorage.getItem(CLIENT_ID_KEY);
9	  if (!id) {
10	    id = uuidv4();
11	    localStorage.setItem(CLIENT_ID_KEY, id);
12	  }
