16	/**
17	 * Enqueues a mutation for eventual sync. Called instead of a direct API call
18	 * when the app is offline, or as part of an optimistic-update flow.
19	 */
20	export async function enqueue(
21	  entityType: EntityType,
22	  operation: MutationOperation,
23	  payload: Record<string, unknown>,
24	  entityId?: string,
25	): Promise<number> {
26	  const mutation: QueuedMutation = {
27	    idempotency_key: uuidv4(),
28	    client_id: getClientId(),
29	    entity_type: entityType,
30	    entity_id: entityId,
31	    operation,
32	    payload,
33	    status: 'pending',
34	    retry_count: 0,
35	    created_at: Date.now(),
36	  };
37	  return db.mutations.add(mutation);
38	}
39	
40	/** Returns all pending mutations sorted by creation time (drain order). */
41	export function getPendingMutations(): Promise<QueuedMutation[]> {
42	  return db.mutations
43	    .where('status')
44	    .equals('pending')
45	    .sortBy('created_at');
46	}
47	
48	/** Marks a mutation as successfully applied and removes it from the queue. */
49	export async function markApplied(seq: number): Promise<void> {
50	  await db.mutations.delete(seq);
51	}
52	
53	/** Marks a mutation as rejected (server refused, no retry). */
54	export async function markRejected(seq: number, error: string): Promise<void> {
55	  await db.mutations.update(seq, { status: 'rejected', error });
56	}
57	
58	/** Increments the retry count and resets status to pending for retry. */
59	export async function scheduleRetry(seq: number): Promise<void> {
60	  const m = await db.mutations.get(seq);
61	  if (!m) return;
62	  await db.mutations.update(seq, {
63	    status: 'pending',
64	    retry_count: m.retry_count + 1,
65	    last_attempt_at: Date.now(),
66	  });
67	}
68	
69	/** Returns the total count of pending mutations (badge indicator). */
70	export function pendingCount(): Promise<number> {
71	  return db.mutations.where('status').equals('pending').count();
72	}
73	
74	/** Clears all applied/rejected mutations older than `maxAgeMs`. */
75	export async function pruneProcessed(maxAgeMs = 7 * 24 * 60 * 60 * 1000): Promise<void> {
76	  const cutoff = Date.now() - maxAgeMs;
77	  await db.mutations
78	    .where('status')
79	    .anyOf(['rejected'])
