// RateLimit implements a simple per-IP token bucket rate limiter.
func RateLimit(rps int) gin.HandlerFunc {
	type bucket struct {
		tokens  int
		lastAdd time.Time
	}
	var mu sync.Mutex
	buckets := map[string]*bucket{}

	return func(c *gin.Context) {
		ip := c.ClientIP()
		mu.Lock()
		b, ok := buckets[ip]
		if !ok {
			b = &bucket{tokens: rps, lastAdd: time.Now()}
			buckets[ip] = b
		}
		// Refill tokens
		elapsed := time.Since(b.lastAdd)
		refill := int(elapsed.Seconds()) * rps
		if refill > 0 {
			b.tokens += refill
			if b.tokens > rps*10 {
				b.tokens = rps * 10
			}
			b.lastAdd = time.Now()
		}
		if b.tokens <= 0 {
			mu.Unlock()
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error": gin.H{"code": "RATE_LIMITED", "message": "too many requests"},
			})
			return
		}
		b.tokens--
		mu.Unlock()
		c.Next()
	}
}

// CORS sets cross-origin headers for listed origins."}

