import "testing"

func TestSyncEntityTypes(t *testing.T) {
	valid := map[string]bool{"items": true, "group_buys": true, "orders": true, "members": true}
	if len(valid) != 4 {
		t.Errorf("expected 4 sync entity types, got %d", len(valid))
	}
